content:
{
  "sentences": [
    {
      "text": "那個人長得很高，而且很瘦。",
      "pinyin": "Nà ge rén zhǎng de hěn gāo, érqiě hěn shòu.",
      "pinyin_numeric": "na4 ge4 ren2 zhang3 de5 hen3 gao1, er2 qie3 hen3 shou4.",
      "translation_en": "That person is very tall and also very thin.",
      "translation_ko": "그 사람은 키가 매우 크고, 또한 매우 날씬합니다."
    },
    {
      "text": "我妹妹很活潑，她喜歡唱歌和跳舞。",
      "pinyin": "Wǒ mèimei hěn huópō, tā xǐhuān chànggē hé tiàowǔ.",
      "pinyin_numeric": "wo3 mei4 mei5 hen3 huo2 po1, ta1 xi3 huan1 chang4 ge1 he2 tiao4 wu3.",
      "translation_en": "My younger sister is very lively; she likes singing and dancing.",
      "translation_ko": "제 여동생은 매우 활발해서 노래 부르고 춤추는 것을 좋아합니다."
    },
    {
      "text": "他戴眼鏡，看起來很認真。",
      "pinyin": "Tā dài yǎnjìng, kàn qǐlái hěn rènzhēn.",
      "pinyin_numeric": "ta1 dai4 yan3 jing4, kan4 qi3 lai2 hen3 ren4 zhen1.",
      "translation_en": "He wears glasses and looks very serious.",
      "translation_ko": "그는 안경을 쓰고 있어서 매우 진지해 보입니다."
    },
    {
      "text": "我哥哥很幽默，他說話很有趣。",
      "pinyin": "Wǒ gēge hěn yōumò, tā shuōhuà hěn yǒuqù.",
      "pinyin_numeric": "wo3 ge1 ge5 hen3 you1 mo4, ta1 shuo1 hua4 hen3 you3 qu4.",
      "translation_en": "My older brother is very humorous; his speech is very interesting.",
      "translation_ko": "제 오빠는 매우 유머러스해서 말하는 것이 아주 재미있습니다."
    },
    {
      "text": "那個女生很漂亮，而且個性很溫柔。",
      "pinyin": "Nà ge nǚshēng hěn piàoliang, érqiě gèxìng hěn wēnróu.",
      "pinyin_numeric": "na4 ge4 nü3 sheng1 hen3 piao4 liang5, er2 qie3 ge4 xing4 hen3 wen1 rou2.",
      "translation_en": "That girl is very pretty, and her personality is very gentle.",
      "translation_ko": "그 여학생은 매우 예쁘고, 성격도 아주 부드럽습니다."
    },
    {
      "text": "他長得很帥，可是個性有點害羞。",
      "pinyin": "Tā zhǎng de hěn shuài, kěshì gèxìng yǒudiǎn hàixiū.",
      "pinyin_numeric": "ta1 zhang3 de5 hen3 shuai4, ke3 shi4 ge4 xing4 you3 dian3 hai4 xiu1.",
      "translation_en": "He is very handsome, but his personality is a bit shy.",
      "translation_ko": "그는 매우 잘생겼지만, 성격이 조금 부끄러움을 탑니다."
    },
    {
      "text": "我朋友很聰明，他學中文學得很快。",
      "pinyin": "Wǒ péngyou hěn cōngmíng, tā xué Zhōngwén xué de hěn kuài.",
      "pinyin_numeric": "wo3 peng2 you5 hen3 cong1 ming2, ta1 xue2 Zhong1 wen2 xue2 de5 hen3 kuai4.",
      "translation_en": "My friend is very smart; he learns Chinese very quickly.",
      "translation_ko": "제 친구는 매우 똑똑해서 중국어를 아주 빨리 배웁니다."
    },
    {
      "text": "那個老人年紀很大，可是看起來很年輕。",
      "pinyin": "Nà ge lǎorén niánjì hěn dà, kěshì kàn qǐlái hěn niánqīng.",
      "pinyin_numeric": "na4 ge4 lao3 ren2 nian2 ji4 hen3 da4, ke3 shi4 kan4 qi3 lai2 hen3 nian2 qing1.",
      "translation_en": "That old person is very old in age, but looks very young.",
      "translation_ko": "그 노인은 나이가 많지만, 매우 젊어 보입니다."
    },
    {
      "text": "她穿著黑色的衣服，看起來很大方。",
      "pinyin": "Tā chuān zhe hēisè de yīfu, kàn qǐlái hěn dàfāng.",
      "pinyin_numeric": "ta1 chuan1 zhe5 hei1 se4 de5 yi1 fu5, kan4 qi3 lai2 hen3 da4 fang1.",
      "translation_en": "She is wearing black clothes and looks very generous.",
      "translation_ko": "그녀는 검은색 옷을 입고 있어서 매우 대범해 보입니다."
    },
    {
      "text": "我認識一個很友善的人，他喜歡幫助別人。",
      "pinyin": "Wǒ rènshi yī ge hěn yǒushàn de rén, tā xǐhuān bāngzhù biérén.",
      "pinyin_numeric": "wo3 ren4 shi5 yi1 ge4 hen3 you3 shan4 de5 ren2, ta1 xi3 huan1 bang1 zhu4 bie2 ren2.",
      "translation_en": "I know a very friendly person; he likes to help others.",
      "translation_ko": "저는 매우 친근한 사람을 아는데, 그는 다른 사람을 돕는 것을 좋아합니다."
    }
  ]
}
